// 获取输入的文章内容
const content = $input.first().json.new_content;

// 定义 HTML 结构的开头部分，设置整体的样式
let html = `
<div style="font-family: 'Microsoft YaHei', sans-serif; line-height: 1.8; padding: 0 16px; margin: 0 auto; max-width: 800px;">
`;

// 对文章内容进行分段处理
const paragraphs = content.split('\n');
let inList = false; // 跟踪是否在列表中

paragraphs.forEach(paragraph => {
    // 处理加粗语法：将 ****内容**** 替换为 <strong>内容</strong>
    let processedParagraph = paragraph;
    if (processedParagraph.includes('****')) {
        processedParagraph = processedParagraph.replace(/\*\*\*(.*?)\*\*\*/g, '<strong>$1</strong>');
    }

    // 处理小标题（以###开头的行）
    if (paragraph.startsWith('###')) {
        // 如果之前在列表中，先关闭列表
        if (inList) {
            html += '</ul>';
            inList = false;
        }
        const title = paragraph.substring(3);
        html += `<h3 style="margin-top: 24px; margin-bottom: 16px; font-size: 20px; color: #800000; font-weight: bold;">${title}</h3>`;
    } 
    // 处理分割线（内容为---的行）
    else if (paragraph.trim() === '---') {
        // 如果之前在列表中，先关闭列表
        if (inList) {
            html += '</ul>';
            inList = false;
        }
        html += `<hr style="border: none; border-top: 1px solid #eee; margin: 24px 0;">`;
    } 
    // 处理列表项（以-开头的行）
    else if (paragraph.trim().startsWith('- ')) {
        const listItem = paragraph.trim().substring(2);
        // 如果不在列表中，开始列表
        if (!inList) {
            html += `<ul style="margin-top: 8px; margin-bottom: 8px; padding-left: 24px;">`;
            inList = true;
        }
        html += `<li style="margin-bottom: 6px;">${listItem}</li>`;
    } 
    // 处理普通段落
    else if (paragraph.trim() !== '') {
        // 如果之前在列表中，先关闭列表
        if (inList) {
            html += '</ul>';
            inList = false;
        }
        html += `<p style="margin-top: 0; margin-bottom: 16px; color: #555;">${processedParagraph}</p>`;
    }
});

// 关闭<ul>标签（如果有打开的话）
if (inList) {
    html += '</ul>';
}

// 关闭最外层的div标签
html += '</div>';

// 输出生成的HTML
return [{
  json: {
    htmlContent: html
  }
}];

